export enum GameType {
    League = 0,
    Friendly = 1,
    Cup = 2,
    Any = 3
}

export enum ResultType
{
    Win = 0,
    Loss = 1,
    Draw = 2
}

export enum GameLocation
{
    Home = 0,
    Away = 1,
}

export enum Position{
    GK = 0,
    Defender = 1,
    Midfielder = 2,
    Strikger = 3
}
